import BacIIPoster from '../assets/category-images/posters/bacii-poster.jpeg'

export const BacIIPage = () => {
    return (
        <div>
            <DetailCategory 
                mainCategory={mainBacIICategoryData}
                subCategory={bacIICategoryData}
                poster={true}
                posterBg={BacIIPoster}
            />
        </div>
    )
}
